// core/tree/engine/TreeEngine.ts

import type { TreeNode } from '../models/TreeNode';
import type { ExpandedKeys } from '../models/ExpandedKeys';
import type {
  SelectionValue,
} from '../models/Selection';

import { createTreeEvent } from './TreeEvents';
import {
  toggleExpansion,
  expandAll,
  collapseAll,
} from './TreeExpansion';
import { filterTree } from './TreeFiltering';
import { isLazyNode, createLazyExpandEvent } from './TreeLazy';

import { toggleMultipleSelection } from './TreeSelection.multiple';
import { toggleCheckboxSelection } from './TreeSelection.checkbox';

export interface TreeEngineProps {
  nodes?: TreeNode[];

  /** Selection */
  selectionMode?: 'single' | 'multiple' | 'checkbox';
  selectionKeys?: SelectionValue;
  metaKeySelection?: boolean;

  /** Expansion */
  expandedKeys?: ExpandedKeys;

  /** Filtering */
  filterValue?: string;
  filterBy?: string;
  filterMode?: 'lenient' | 'strict';

  /** Callbacks */
  onSelectionChange?: (e: any) => void;
  onToggle?: (e: any) => void;
  onExpand?: (e: any) => void;
  onCollapse?: (e: any) => void;
}

export function createTreeEngine(props: TreeEngineProps) {
  const {
    nodes,
    selectionMode = 'single',
    selectionKeys,
    expandedKeys,
    metaKeySelection = true,

    filterValue,
    filterBy,
    filterMode,

    onSelectionChange,
    onToggle,
    onExpand,
    onCollapse,
  } = props;

  // -----------------------------
  // Controlled vs uncontrolled
  // -----------------------------

  let _selection: SelectionValue = selectionKeys ?? null;
  let _expanded: ExpandedKeys = expandedKeys ?? {};

  const selectionControlled = selectionKeys !== undefined;
  const expansionControlled = expandedKeys !== undefined;

  // -----------------------------
  // Derived tree (filtering)
  // -----------------------------

  // Filter whenever filterValue is provided — the `filter` prop only controls
  // whether the built-in filter UI is rendered, not the engine itself.
  const visibleNodes =
    filterValue
      ? filterTree(nodes, filterValue, { filterBy, filterMode })
      : nodes;

  // -----------------------------
  // Engine API
  // -----------------------------

  return {
    state: {
      get selection() {
        return selectionControlled ? selectionKeys! : _selection;
      },
      get expandedKeys() {
        return expansionControlled ? expandedKeys! : _expanded;
      },
      get nodes() {
        return visibleNodes;
      },
    },

    actions: {
      // -----------------------------
      // Selection
      // -----------------------------
      selectNode(
        key: string,
        options?: {
          metaKeyPressed?: boolean;
          originalEvent?: any;
        }
      ) {
        let next: SelectionValue = _selection;

        if (selectionMode === 'single') {
          next = key;
        }

        if (selectionMode === 'multiple') {
          const isTouch =
            typeof navigator !== 'undefined'
              ? navigator.maxTouchPoints > 0
              : true;
          const effectiveMetaKey = isTouch ? false : metaKeySelection;
          next = toggleMultipleSelection(
            _selection as Record<string, boolean> | null,
            { key } as any, // TreeNode key is all we need
            effectiveMetaKey
          );
        }

        if (selectionMode === 'checkbox') {
          next = toggleCheckboxSelection(
              _selection as unknown as Record<string, { checked: boolean; }> | null,
              { key } as any,
              nodes,
          ) as unknown as SelectionValue;
        }

        // uncontrolled → store internally
        if (!selectionControlled) {
          _selection = next;
        }

        // ALWAYS emit PrimeReact-compatible event
        onSelectionChange?.(
          createTreeEvent(next, options?.originalEvent)
        );
      },

      // -----------------------------
      // Expansion
      // -----------------------------
      toggleNode(node: TreeNode, originalEvent?: any) {
        const key = node.key;

        // Lazy expand
        if (isLazyNode(node)) {
          onExpand?.(createLazyExpandEvent(node, originalEvent));
          return;
        }

        const next = toggleExpansion(
          expansionControlled ? expandedKeys : _expanded,
          key
        );

        if (!expansionControlled) {
          _expanded = next;
        }

        onToggle?.(createTreeEvent(next, originalEvent));

        if (next[key]) {
          onExpand?.(createTreeEvent(node, originalEvent));
        } else {
          onCollapse?.(createTreeEvent(node, originalEvent));
        }
      },

      expandAll(originalEvent?: any) {
        const next = expandAll(nodes);

        if (!expansionControlled) {
          _expanded = next;
        }

        onToggle?.(createTreeEvent(next, originalEvent));
      },

      collapseAll(originalEvent?: any) {
        const next = collapseAll();

        if (!expansionControlled) {
          _expanded = next;
        }

        onToggle?.(createTreeEvent(next, originalEvent));
      },
    },
  };
}
